function report = runRasterTextureVisualization(sceneNumber, options)
%RUNRASTERTEXTUREVISUALIZATION Inspect one ignored raster-texture scene.
%
% The generated images and truth are loaded from
% test_data/generated/raster_texture_50m_v1 by default. They are not
% regenerated, copied, or committed. All algorithm outputs and figures are
% enabled by default, including raw transported T3 and the frozen robust
% hybrid. The T3 cost volume remains volume-free unless explicitly retained.
%
%   1  source10 along-track 50 m slope
%   2  source102 cross-track 50 m slope
%   3  source10 along-track 50 m step
%   4  source102 cross-track 50 m step
%   5  source102 radial sinc, +60 m center and 110 m lobe spacing
%   6  source10 curved hillside with four vertical-walled buildings
%
% Example:
%   report = runRasterTextureVisualization(1);
%   report = runRasterTextureVisualization(2, NumWorkers=14);
%
% Traceability: algo/main.tex Algorithm 1; Secs. 6.2, 8.4, 10.4--10.5,
% 11.2--11.4, and 14.6; Eqs. (71)--(76) and (121)--(133).

arguments
    sceneNumber (1, 1) double ...
        {mustBeFinite, mustBeInteger, ...
        mustBeMember(sceneNumber, 1:6)} = 1
    options.DatasetName (1, 1) string ...
        {mustBeDatasetName} = "raster_texture_50m_v1"
    options.DatasetDirectory (1, 1) string = ""
    options.Display (1, 1) logical = true
    options.UseParallel (1, 1) logical = true
    options.NumWorkers (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.MaximumPendingTiles (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.TileSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [128, 128]
    options.LabelBlockSize (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 4
    options.HeightLabelMode (1, 1) string ...
        {mustBeMember(options.HeightLabelMode, ...
        ["observability", "three-plane"])} = "observability"
    options.CostCurveFraction (1, 2) double ...
        {mustBeFinite, mustBeGreaterThanOrEqual( ...
        options.CostCurveFraction, 0), mustBeLessThanOrEqual( ...
        options.CostCurveFraction, 1)} = [0.5, 0.5]
    options.StoreResearchCostVolumes (1, 1) logical = false
    options.CpuImplementation (1, 1) string ...
        {mustBeMember(options.CpuImplementation, ...
        ["optimized", "reference"])} = "optimized"
    options.WorkingPrecision (1, 1) string ...
        {mustBeMember(options.WorkingPrecision, ...
        ["single", "double"])} = "single"
end

root = fileparts(fileparts(mfilename("fullpath")));
oldPath = path;
addpath(fullfile(root, "src"));
cleanup = onCleanup(@() path(oldPath));
if strlength(options.DatasetDirectory) == 0
    datasetDir = fullfile(root, "test_data", "generated", ...
        options.DatasetName);
else
    datasetDir = char(options.DatasetDirectory);
end
datasetFile = fullfile(datasetDir, "dataset_manifest.json");
if ~isfile(datasetFile)
    error("runRasterTextureVisualization:DatasetNotFound", ...
        ["Generated dataset manifest not found: %s\n" ...
        "Run generateLocalRasterTextureDataset first."], datasetFile);
end

timer = tic;
dataset = jsondecode(fileread(datasetFile));
if ~isfield(dataset, "scenes") || numel(dataset.scenes) < sceneNumber
    error("runRasterTextureVisualization:SceneNotFound", ...
        "Dataset %s does not contain enumerated scene %d.", ...
        datasetFile, sceneNumber);
end
c = dataset.scenes(sceneNumber);
sceneDir = fullfile(datasetDir, string(c.identifier));
manifestFile = fullfile(sceneDir, "manifest.json");
referenceFile = fullfile(sceneDir, "reference.tif");
movingFile = fullfile(sceneDir, "moving.tif");
truthFile = fullfile(sceneDir, "truth.mat");
required = [string(manifestFile), string(referenceFile), ...
    string(movingFile), string(truthFile)];
if any(~isfile(required))
    error("runRasterTextureVisualization:IncompleteScene", ...
        "Generated scene %d is missing one or more required files in %s.", ...
        sceneNumber, sceneDir);
end

c = jsondecode(fileread(manifestFile));
reference = imread(referenceFile);
moving = imread(movingFile);
t = load(truthFile);
renderer = rendererFromManifest(c, t);
inputSeconds = toc(timer);

pair = struct("ReferenceImage", reference, "MovingImage", moving, ...
    "ReferenceValid", logical(t.referenceValid), ...
    "MovingValid", logical(t.movingValid));
truthValid = logical(t.correspondenceValid) ...
    & logical(t.referenceSurfaceValid);
validHeight = t.heightMetres(logical(t.referenceSurfaceValid) ...
    & isfinite(t.heightMetres));
padding = max(10, 0.2 .* max(max(validHeight) - min(validHeight), 1));
searchRange = [min(validHeight) - padding, max(validHeight) + padding];

splitFile = fullfile(root, "config", "synthetic", ...
    "degraded_split_v1.json");
split = jsondecode(fileread(splitFile));
scene = struct( ...
    "Number", sceneNumber, "Identifier", string(c.identifier), ...
    "Suite", "local-raster-texture", ...
    "FixtureFile", string(manifestFile), ...
    "DatasetName", string(dataset.datasetName), ...
    "Radiometry", "none", "InputKind", "persisted-raster-texture", ...
    "Renderer", renderer, "Pair", pair, ...
    "TruthHeightMetres", double(t.heightMetres), ...
    "TruthCorrespondenceXY", double(t.correspondenceXY), ...
    "TruthValid", truthValid, "SearchRangeMetres", searchRange, ...
    "TargetMotionPerLabelPixels", fieldOr(c, ...
    "targetMotionPerLabelPixels", 0.25), ...
    "Configuration", split, "InputSeconds", inputSeconds);

report = runSyntheticHeightVisualization(scene, ...
    Display=options.Display, UseParallel=options.UseParallel, ...
    NumWorkers=options.NumWorkers, TileSize=options.TileSize, ...
    MaximumPendingTiles=options.MaximumPendingTiles, ...
    LabelBlockSize=options.LabelBlockSize, ...
    HeightLabelMode=options.HeightLabelMode, ...
    CostCurveFraction=options.CostCurveFraction, ...
    StoreResearchCostVolumes=options.StoreResearchCostVolumes, ...
    CpuImplementation=options.CpuImplementation, ...
    WorkingPrecision=options.WorkingPrecision);
clear cleanup
end

function renderer = rendererFromManifest(c, truth)
azimuth = double(c.lookAzimuthDegrees);
h = [sind(azimuth), cosd(azimuth)];
q = [cosd(azimuth), -sind(azimuth)];
slope = double(c.surfaceSlopeENU(:)).';
if string(c.surfaceType) == "radial-sinc"
    along = 0;
    cross = 0;
else
    along = atand(slope * h.');
    cross = atand(slope * q.');
end
height = double(truth.heightMetres);
valid = logical(truth.referenceSurfaceValid) & isfinite(height);
padding = max(10, 0.2 .* max(max(height(valid)) - min(height(valid)), 1));
searchRange = [min(height(valid)) - padding, ...
    max(height(valid)) + padding];
renderer = SyntheticPinholeRenderer(string(c.identifier), ...
    double(c.imageSize), Suite="local-raster-texture", ...
    BitDepth=double(c.outputBitDepth), ...
    HorizontalFieldOfViewDegrees=fieldOr(c, ...
    "horizontalFieldOfViewDegrees", 1), ...
    CenterGsdMetres=double(c.centerGsdMetres), ...
    MeanObliquityDegrees=double(c.meanObliquityDegrees), ...
    ConvergenceDegrees=double(c.convergenceDegrees), ...
    LookAzimuthDegrees=azimuth, ...
    ReferenceRollDegrees=fieldOr(c, "referenceRollDegrees", 0), ...
    MovingRollDegrees=fieldOr(c, "movingRollDegrees", 0), ...
    TrueHeightMetres=double(c.trueHeightMetres), ...
    AlongTrackSlopeDegrees=along, CrossTrackSlopeDegrees=cross, ...
    SurfaceType=string(c.surfaceType), ...
    StepHeightMetres=double(c.stepHeightMetres), ...
    StepDirection=string(c.stepDirection), ...
    StepPositionMetres=fieldOr(c, "stepPositionMetres", 0), ...
    SincAmplitudeMetres=fieldOr(c, "sincAmplitudeMetres", 60), ...
    SincLobeSpacingMetres=fieldOr(c, "sincLobeSpacingMetres", 110), ...
    SincCenterENU=fieldOr(c, "sincCenterENU", [0, 0]), ...
    TerrainCurvaturePerMetre=fieldOr(c, ...
    "terrainCurvaturePerMetre", 0), ...
    CurvatureCenterENU=fieldOr(c, "curvatureCenterENU", [0, 0]), ...
    Buildings=buildingField(c), ...
    SearchRangeMetres=searchRange, ...
    TargetMotionPerLabelPixels=fieldOr(c, ...
    "targetMotionPerLabelPixels", 0.25), ...
    Supersample=fieldOr(c, "supersample", 2), ...
    PsfSigmaPixels=fieldOr(c, "psfSigmaPixels", 0.55));
end

function value = fieldOr(s, name, fallback)
if isfield(s, name)
    value = double(s.(name));
else
    value = fallback;
end
end

function value = buildingField(s)
if ~isfield(s, "buildings") || isempty(s.buildings)
    value = zeros(0, 5);
else
    value = double(s.buildings);
end
end

function mustBeDatasetName(name)
if strlength(name) == 0 || contains(name, ["/", "\"])
    error("runRasterTextureVisualization:InvalidDatasetName", ...
        "DatasetName must be one nonempty path component.");
end
end
